# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql

def lambda_handler(event, context):
    # Database connection details
    rds_host = "your_rds_endpoint"
    name = "your_username"
    password = "your_password"
    db_name = "your_database"

    try:
        # Establish a database connection
        conn = pymysql.connect(host=rds_host, user=name, passwd=password, db=db_name)
        cursor = conn.cursor()

        # Extract search parameters from event
        search_params = event.get('queryStringParameters', {})
        query_parts = []

        # Build SQL query dynamically based on search parameters
        for key, value in search_params.items():
            query_parts.append(f"{key} LIKE '%{value}%'")

        if query_parts:
            sql_query = "SELECT * FROM products WHERE " + " AND ".join(query_parts)
        else:
            sql_query = "SELECT * FROM products"

        # Execute the SQL query
        cursor.execute(sql_query)

        # Fetch and return results
        result = cursor.fetchall()
        response = {
            'statusCode': 200,
            'body': json.dumps(result, default=str),
            'headers': {
                'Content-Type': 'application/json'
            }
        }

    except pymysql.Error as e:
        response = {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)}),
            'headers': {
                'Content-Type': 'application/json'
            }
        }

    finally:
        # Close the database connection
        if conn:
            cursor.close()
            conn.close()

    return response